@use "../../styles/theme.scss" as theme;
@use "../../styles/mixins.scss" as mixins;

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes fadeOut {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideDown {
  from {
    opacity: 1;
    transform: translateY(0);
  }
  to {
    opacity: 0;
    transform: translateY(20px);
  }
}

@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.8);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes scaleOut {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.9);
  }
}

.nightOverlay {
  @include mixins.flexCenter(column);
  position: absolute;
  top: 0;
  left: 0;
  width: 75%;
  height: 100%;
  background: linear-gradient(135deg, #1a1a2e 0%, #0f0f1e 100%);
  color: theme.$color-text-primary;
  gap: 2rem;
  padding: 2rem;
  overflow: hidden;
  border-radius: theme.$border-radius-big;
  box-shadow:
    inset 0 0 80px rgba(0, 0, 0, 0.5),
    0 8px 32px rgba(0, 0, 0, 0.4);
  z-index: 10;
  animation: fadeIn 0.4s ease-out;

  &.hiding {
    animation: fadeOut 0.4s ease-out forwards;
  }
}

.nightIcon {
  font-size: 8rem;
  opacity: 0.8;
  animation:
    scaleIn 0.6s ease-out 0.2s backwards,
    pulse 3s ease-in-out 1s infinite;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 0.6;
    transform: scale(1);
  }
  50% {
    opacity: 1;
    transform: scale(1.1);
  }
}

.nightTitle {
  font-size: 3rem;
  font-weight: 700;
  text-align: center;
  margin: 0;
  text-shadow: 0 0 20px rgba(255, 255, 255, 0.5);
  animation: slideUp 0.6s ease-out 0.4s backwards;
}

.nightSubtitle {
  font-size: 1.6rem;
  text-align: center;
  opacity: 0.8;
  margin: 0;
  max-width: 50rem;
  animation: slideUp 0.6s ease-out 0.6s backwards;
}

.nightInfo {
  @include mixins.flexCenter(column);
  gap: 1rem;
  padding: 2rem;
  background: rgba(theme.$color-dark-secondary, 0.8);
  border-radius: theme.$border-radius;
  border: 1px solid rgba(theme.$color-light-tertiary, 0.2);
  animation: slideUp 0.6s ease-out 0.8s backwards;
}

.nightInfoText {
  font-size: 1.4rem;
  margin: 0;
  opacity: 0.9;
}

